                <div style={{ fontSize: '1rem', fontWeight: 600 }}>Actividad Reciente</div>
                <Link to="/contracts" style={{ fontSize: '0.875rem', color: 'var(--primary)', textDecoration: 'none' }}>Ver todo</Link>
            </div>
            <div>
                {activities.length === 0 ? (
                    <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--text-muted)' }}>
                        No hay actividad reciente
                    </div>
                ) : (
                    activities.map((item) => (
                        <div key={item.id} style={{
                            padding: '1rem 1.25rem',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '1rem',
                            borderBottom: '1px solid var(--border-light)',
                            transition: 'background 0.2s'
                        }}
                            onMouseEnter={(e) => e.currentTarget.style.background = 'var(--background)'}
                            onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}
                        >
                            <div style={{
                                width: '36px',
                                height: '36px',
                                borderRadius: '50%',
                                background: 'var(--primary-light)',
                                color: 'var(--primary)',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center'
                            }}>
                                <FileText size={18} />
                            </div>
                            <div style={{ flex: 1 }}>
                                <div style={{ fontSize: '0.9rem', fontWeight: 500, color: 'var(--text-main)' }}>
                                    {item.title}
                                </div>
                                <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                                    {new Date(item.date).toLocaleDateString('es-ES', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' })} ÔÇó {item.subtitle}
                                </div>
                            </div>
                            <ChevronRight size={16} color="var(--text-muted)" />
                        </div>
                    ))
                )}
            </div>
        </div>
    )
}

import { useState, useEffect, useRef } from 'react';
import { Send, Phone, Mail, User, Paperclip, X, FileIcon, Download, FileText } from 'lucide-react';
import { Message, uploadAttachment } from '../lib/messaging-service';

interface ChatWindowProps {
    customerName: string;
    customerContact: string;
    messages: Message[];
    onSendMessage: (content: string, subject?: string, attachments?: Message['attachments']) => void;
    isLoading?: boolean;
    channel: 'email' | 'whatsapp';
    disableInput?: boolean;
}

const STYLES = {
    container: {
        display: 'flex',
        flexDirection: 'column' as const,
        height: '100%',
        backgroundColor: '#ffffff',
        background: 'linear-gradient(135deg, #ffffff 0%, #f8faff 100%)'
    },
    header: {
        padding: '1rem',
        borderBottom: '1px solid #e5e7eb',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        backdropFilter: 'blur(12px)',
        backgroundColor: 'rgba(255, 255, 255, 0.8)',
        position: 'sticky' as const,
        top: 0,
        zIndex: 10,
        boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)'
    },
    avatar: {
        width: '2.5rem',
        height: '2.5rem',
        backgroundColor: '#eff6ff',
        borderRadius: '9999px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        color: '#2563eb',
        boxShadow: 'inset 0 2px 4px 0 rgba(0, 0, 0, 0.06)'
    },
    messagesArea: {
        flex: 1,
        overflowY: 'auto' as const,
        padding: '1rem',
        display: 'flex',
        flexDirection: 'column' as const,
        gap: '1rem',
        backgroundColor: 'transparent',
        backgroundImage: 'radial-gradient(#e5e7eb 1px, transparent 1px)',
        backgroundSize: '20px 20px'
    },
    emptyState: {
        display: 'flex',
        flexDirection: 'column' as const,
        alignItems: 'center',
        justifyContent: 'center',
        height: '100%',
        opacity: 0.4
    },
    inputArea: {
        padding: '1rem',
        borderTop: '1px solid #e5e7eb',
        backgroundColor: 'rgba(255, 255, 255, 0.9)',
        backdropFilter: 'blur(8px)',
        boxShadow: '0 -4px 6px -1px rgba(0, 0, 0, 0.05)'
    },
    sendButton: {
        height: '42px',
        width: '42px',
        borderRadius: '0.75rem',
        boxShadow: '0 10px 15px -3px rgba(59, 130, 246, 0.3)',
        transition: 'transform 0.2s cubic-bezier(0.4, 0, 0.2, 1)',
        padding: 0,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        border: 'none',
        cursor: 'pointer',
        background: '#2563eb',
        color: 'white'
    },
    attachmentPreview: {
        display: 'flex',
        alignItems: 'center',
        gap: '0.5rem',
        padding: '0.5rem',
        background: '#f3f4f6',
        borderRadius: '0.5rem',
        fontSize: '0.75rem',
        marginBottom: '0.5rem',
        border: '1px solid #e5e7eb'
    }
};

export function ChatWindow({ customerName, customerContact, messages, onSendMessage, isLoading, channel, disableInput = false }: ChatWindowProps) {
    const [newMessage, setNewMessage] = useState('');
    const [subject, setSubject] = useState('');
    const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
    const [isUploading, setIsUploading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        scrollToBottom();
    }, [messages]);

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files) {
            setSelectedFiles(prev => [...prev, ...Array.from(e.target.files!)]);
        }
    };

    const removeFile = (index: number) => {
        setSelectedFiles(prev => prev.filter((_, i) => i !== index));
    };

    const handleSend = async () => {
        if (!newMessage.trim() && selectedFiles.length === 0) return;

        setIsUploading(true);
        try {
            let attachments: Message['attachments'] = [];

            for (const file of selectedFiles) {
                const uploaded = await uploadAttachment(file);
                attachments.push(uploaded);
            }

            onSendMessage(newMessage, channel === 'email' ? subject : undefined, attachments.length > 0 ? attachments : undefined);

            setNewMessage('');
            setSubject('');
            setSelectedFiles([]);
        } catch (error) {
            console.error("Error sending message:", error);
        } finally {
            setIsUploading(false);
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleSend();
        }
    };

    return (
        <div style={STYLES.container}>
            {/* Header */}
            <div style={STYLES.header}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                    <div style={STYLES.avatar}>
                        <User size={20} />
                    </div>
                    <div>
                        <div style={{ fontWeight: 600, color: '#111827', lineHeight: 1.2, margin: 0, fontSize: '1rem' }}>{customerName}</div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.75rem', color: '#6b7280', marginTop: '0.125rem' }}>
                            {channel === 'whatsapp' ? <Phone size={12} style={{ color: '#22c55e' }} /> : <Mail size={12} style={{ color: '#60a5fa' }} />}
                            <span style={{ opacity: 0.8 }}>{customerContact}</span>
                        </div>
                    </div>
                </div>
                <div>
                    <span style={{
                        padding: '0.25rem 0.75rem',
                        borderRadius: '9999px',
                        fontSize: '0.75rem',
                        fontWeight: 500,
                        textTransform: 'capitalize',
                        backgroundColor: channel === 'whatsapp' ? '#f0fdf4' : '#eff6ff',
                        color: channel === 'whatsapp' ? '#15803d' : '#1d4ed8',
                        border: `1px solid ${channel === 'whatsapp' ? '#bbf7d0' : '#bfdbfe'}`
                    }}>
                        {channel}
                    </span>
                </div>
            </div>

            {/* Messages Area */}
            <div style={STYLES.messagesArea}>
                {messages.length === 0 ? (
                    <div style={STYLES.emptyState}>
                        <div style={{ padding: '1rem', background: '#f3f4f6', borderRadius: '9999px', marginBottom: '0.75rem' }}>
                            <Send size={32} style={{ color: '#9ca3af' }} />
                        </div>
                        <p style={{ color: '#6b7280', fontWeight: 500, margin: 0 }}>No hay mensajes todav├¡a. Inicia la conversaci├│n.</p>
                    </div>
                ) : (
                    messages.map((msg) => (
                        <div
                            key={msg.id}
                            style={{ width: '100%', display: 'flex', justifyContent: msg.direction === 'inbound' ? 'flex-start' : 'flex-end' }}
                        >
                            <div
                                style={{
                                    maxWidth: '75%',
                                    padding: '0.875rem',
                                    borderRadius: '1rem',
                                    fontSize: '14px',
                                    position: 'relative',
                                    boxShadow: msg.direction === 'inbound' ? '0 1px 2px 0 rgba(0, 0, 0, 0.05)' : '0 10px 15px -3px rgba(59, 130, 246, 0.2)',
                                    backgroundColor: msg.direction === 'inbound' ? '#ffffff' : '#2563eb',
                                    color: msg.direction === 'inbound' ? '#1f2937' : '#ffffff',
                                    border: msg.direction === 'inbound' ? '1px solid #f3f4f6' : 'none',
                                    borderBottomLeftRadius: msg.direction === 'inbound' ? '0' : '1rem',
                                    borderBottomRightRadius: msg.direction === 'inbound' ? '1rem' : '0',
                                    display: 'flex',
                                    flexDirection: 'column',
                                    gap: '0.5rem'
                                }}
                            >
                                {msg.subject && (
                                    <p style={{
                                        margin: 0,
                                        fontWeight: 'bold',
                                        fontSize: '12px',
                                        opacity: 0.9,
                                        borderBottom: msg.direction === 'inbound' ? '1px solid #f1f5f9' : '1px solid rgba(255,255,255,0.2)',
                                        paddingBottom: '0.25rem'
                                    }}>
                                        Asunto: {msg.subject}
                                    </p>
                                )}

                                <p style={{ margin: 0, lineHeight: 1.6, whiteSpace: 'pre-wrap' }}>{msg.content}</p>

                                {msg.attachments && msg.attachments.length > 0 && (
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', marginTop: '0.5rem' }}>
                                        {msg.attachments.map((att, idx) => (
                                            <a
                                                key={idx}
                                                href={att.url}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                style={{
                                                    display: 'flex',
                                                    alignItems: 'center',
                                                    gap: '0.5rem',
                                                    padding: '0.5rem',
                                                    background: msg.direction === 'inbound' ? '#f8fafc' : 'rgba(255,255,255,0.1)',
                                                    borderRadius: '0.5rem',
                                                    textDecoration: 'none',
                                                    color: 'inherit',
                                                    border: msg.direction === 'inbound' ? '1px solid #e2e8f0' : '1px solid rgba(255,255,255,0.2)'
                                                }}
                                            >
                                                <FileIcon style={{ width: 14, height: 14 }} />
                                                <span style={{ fontSize: '11px', flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{att.name}</span>
                                                <Download style={{ width: 12, height: 12 }} />
                                            </a>
                                        ))}
                                    </div>
                                )}

                                <div style={{
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '0.375rem',
                                    marginTop: '0.25rem',
                                    justifyContent: 'flex-end'
                                }}>
                                    <span style={{
                                        fontSize: '10px',
                                        fontWeight: 500,
                                        letterSpacing: '0.025em',
                                        textTransform: 'uppercase' as const,
                                        color: msg.direction === 'inbound' ? '#9ca3af' : 'rgba(219, 234, 254, 0.7)'
                                    }}>
                                        {new Date(msg.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                    </span>
                                    {msg.status && msg.direction !== 'inbound' && (
                                        <span style={{
                                            fontSize: '10px',
                                            fontWeight: 'bold',
                                            color: 'rgba(191, 219, 254, 0.8)'
                                        }}>
                                            ÔÇó {msg.status.toUpperCase()}
                                        </span>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <div style={STYLES.inputArea}>
                {/* Selected Files Preview */}
                {selectedFiles.length > 0 && (
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem', marginBottom: '0.75rem' }}>
                        {selectedFiles.map((file, i) => (
                            <div key={i} style={STYLES.attachmentPreview}>
                                <FileText size={12} style={{ color: '#3b82f6' }} />
                                <span style={{ maxWidth: '120px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{file.name}</span>
                                <button
                                    onClick={() => removeFile(i)}
                                    style={{ color: '#94a3b8', background: 'none', border: 'none', cursor: 'pointer', padding: 0 }}
                                >
                                    <X size={12} />
                                </button>
                            </div>
                        ))}
                    </div>
                )}

                {channel === 'email' && (
                    <div style={{ marginBottom: '0.75rem' }}>
                        <input
                            placeholder="Asunto del correo..."
                            value={subject}
                            onChange={(e) => setSubject(e.target.value)}
                            disabled={isLoading || isUploading || disableInput}
                            style={{
                                width: '100%',
                                height: '36px',
                                fontSize: '13px',
                                borderRadius: '0.5rem',
                                background: '#f8fafc',
                                border: '1px solid #e2e8f0',
                                padding: '0 0.75rem'
                            }}
                        />
                    </div>
                )}

                <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'flex-end' }}>
                    <button
                        onClick={() => fileInputRef.current?.click()}
                        disabled={isLoading || isUploading || disableInput}
                        style={{
                            padding: '0.5rem',
                            borderRadius: '0.5rem',
                            background: '#f1f5f9',
                            color: '#64748b',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            alignSelf: 'center',
                            height: '42px',
                            width: '42px',
                            border: 'none',
                            cursor: 'pointer'
                        }}
                    >
                        <Paperclip size={20} />
                    </button>
                    <input
                        type="file"
                        ref={fileInputRef}
                        onChange={handleFileSelect}
                        multiple
                        style={{ display: 'none' }}
                    />

                    <div style={{ flex: 1, position: 'relative' }}>
                        <input
                            value={newMessage}
                            onChange={(e) => setNewMessage(e.target.value)}
                            placeholder={disableInput ? "Selecciona un contacto..." : "Escribe un mensaje..."}
                            onKeyDown={handleKeyDown}
                            style={{
                                width: '100%',
                                backgroundColor: '#f9fafb',
                                border: '1px solid #e5e7eb',
                                padding: '0.75rem 1rem',
                                borderRadius: '0.75rem',
                                transition: 'all 0.2s',
                                fontSize: '14px'
                            }}
                            disabled={isLoading || isUploading || disableInput}
                        />
                    </div>
                    <button
                        onClick={handleSend}
                        disabled={isLoading || isUploading || (!newMessage.trim() && selectedFiles.length === 0) || disableInput}
                        style={{
                            ...STYLES.sendButton,
                            opacity: (isLoading || isUploading || (!newMessage.trim() && selectedFiles.length === 0) || disableInput) ? 0.5 : 1
                        }}
                    >
                        {isUploading ? (
                            <div style={{ width: '20px', height: '20px', border: '2px solid white', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 1s linear infinite' }} />
                        ) : (
                            <Send size={20} />
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
}

import { useState, useRef } from 'react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { Upload, X, FileText, Loader2, CheckCircle2, AlertCircle } from 'lucide-react';
import { supabase } from '@/shared/lib/supabase';
import { useToast } from '@/hooks/use-toast';
// We will use a fixed overlay/modal approach instead of shadcn Dialog to remove dependencies
import { useEffect } from 'react';

interface TariffUploadDialogProps {
    companyId: string;
    onUploadSuccess?: () => void;
}

interface UploadState {
    file: File;
    progress: number;
    status: 'pending' | 'uploading' | 'processing' | 'completed' | 'error';
    error?: string;
}

export function TariffUploadDialog({ companyId, onUploadSuccess }: TariffUploadDialogProps) {
    const [isOpen, setIsOpen] = useState(false);
    const [uploads, setUploads] = useState<UploadState[]>([]);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const { toast } = useToast();
    const queryClient = useQueryClient();

    // Mutation to create a batch
    const createBatchMutation = useMutation({
        mutationFn: async () => {
            const { data, error } = await supabase
                .from('tariff_batches')
                .insert({
                    company_id: companyId,
                    uploaded_by: (await supabase.auth.getUser()).data.user?.id,
                    status: 'processing',
                    file_count: uploads.length
                })
                .select()
                .single();

            if (error) throw error;
            return data;
        }
    });

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            const newFiles = Array.from(e.target.files).map(file => ({
                file,
                progress: 0,
                status: 'pending' as const
            }));
            setUploads(prev => [...prev, ...newFiles]);
        }
        // Reset input
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
        }
    };

    const removeFile = (index: number) => {
        setUploads(prev => prev.filter((_, i) => i !== index));
    };

    const startUpload = async () => {
        if (uploads.length === 0) return;

        try {
            // 1. Create Batch
            const batch = await createBatchMutation.mutateAsync();

            // 2. Upload files and create records
            const uploadPromises = uploads.map(async (uploadState, index) => {
                try {
                    setUploads(prev => prev.map((u, i) => i === index ? { ...u, status: 'uploading', progress: 0 } : u));

                    const fileExt = uploadState.file.name.split('.').pop();
                    const fileName = `${companyId}/${batch.id}/${crypto.randomUUID()}.${fileExt}`;

                    // Upload to Storage
                    const { error: uploadError } = await supabase.storage
                        .from('tariff-pdfs')
                        .upload(fileName, uploadState.file);

                    if (uploadError) throw uploadError;

                    setUploads(prev => prev.map((u, i) => i === index ? { ...u, progress: 50 } : u));

                    // Create DB record
                    const { data: fileRecord, error: dbError } = await supabase
                        .from('tariff_files')
                        .insert({
                            company_id: companyId,
                            batch_id: batch.id,
                            filename: uploadState.file.name,
                            storage_path: fileName,
                            file_size_bytes: uploadState.file.size,
                            mime_type: uploadState.file.type,
                            extraction_status: 'pending'
                        })
                        .select()
                        .single();

                    if (dbError) throw dbError;

                    setUploads(prev => prev.map((u, i) => i === index ? { ...u, status: 'processing', progress: 75 } : u));

                    // Trigger Edge Function
                    const { data: extractedDataResponse, error: funcError } = await supabase.functions.invoke('process-tariff-sheet', {
                        body: {
                            company_id: companyId,
                            file_path: fileName,
                            file_id: fileRecord.id, // Pass ID to update status on completion
                            batch_id: batch.id
                        }
                    });

                    if (funcError) {
                        console.error("Edge function error:", funcError);
                        // Don't fail the whole upload if just the OCR fails, but mark it
                        setUploads(prev => prev.map((u, i) => i === index ? { ...u, status: 'error', error: 'AI Processing Failed', progress: 100 } : u));
                    } else {
                        // Handle potential array response (even if edge function returns single object, we wrap it, but it should return array now)
                        const extractedDataArray = Array.isArray(extractedDataResponse) ? extractedDataResponse : [extractedDataResponse];

                        try {
                            for (const extractedData of extractedDataArray) {
                                // Create Tariff Version from Extracted Data
                                const { data: tariffVersion, error: tvError } = await supabase
                                    .from('tariff_versions')
                                    .insert({
                                        company_id: companyId,
                                        batch_id: batch.id,
                                        file_id: fileRecord.id,
                                        supplier_name: extractedData.supplier_name || 'Desconocida',
                                        tariff_name: extractedData.tariff_name || 'Tarifa Importada',
                                        tariff_type: extractedData.tariff_type || '2.0TD',
                                        valid_from: extractedData.valid_from || new Date().toISOString(),
                                        valid_to: extractedData.valid_to || null,
                                        is_active: true
                                    })
                                    .select()
                                    .single();

                                if (tvError) throw tvError;

                                const components = [];

                                // Energy Prices
                                for (let p = 1; p <= 6; p++) {
                                    const val = extractedData[`energy_p${p}`];
                                    if (val !== null && val !== undefined) {
                                        components.push({
                                            company_id: companyId,
                                            tariff_version_id: tariffVersion.id,
                                            component_type: 'energy_price',
                                            period: `P${p}`,
                                            price_eur_kwh: Number(val)
                                        });
                                    }
                                }

                                // Power Prices
                                for (let p = 1; p <= 6; p++) {
                                    const val = extractedData[`power_p${p}`];
                                    if (val !== null && val !== undefined) {
                                        components.push({
                                            company_id: companyId,
                                            tariff_version_id: tariffVersion.id,
                                            component_type: 'power_price',
                                            period: `P${p}`,
                                            price_eur_kw_year: Number(val)
                                        });
                                    }
                                }

                                // Fixed Fee
                                if (extractedData.fixed_fee !== null && extractedData.fixed_fee !== undefined) {
                                    components.push({
                                        company_id: companyId,
                                        tariff_version_id: tariffVersion.id,
                                        component_type: 'fixed_fee',
                                        fixed_price_eur_month: Number(extractedData.fixed_fee)
                                    });
                                }

                                if (components.length > 0) {
                                    const { error: cError } = await supabase
                                        .from('tariff_components')
                                        .insert(components);

                                    if (cError) throw cError;
                                }
                            }

                            setUploads(prev => prev.map((u, i) => i === index ? { ...u, status: 'completed', progress: 100 } : u));

                        } catch (creationError: any) {
                            console.error("Error creating tariff from data:", creationError);
                            setUploads(prev => prev.map((u, i) => i === index ? { ...u, status: 'error', error: 'Import Failed', progress: 100 } : u));
                        }
                    }
                } catch (err: any) {
                    console.error("Upload failed for file:", uploadState.file.name, err);
                    setUploads(prev => prev.map((u, i) => i === index ? { ...u, status: 'error', error: err.message } : u));
                }
            });

            await Promise.all(uploadPromises);

            toast({
                title: "Upload Complete",
                description: `Processed ${uploads.length} files.`,
            });

            onUploadSuccess?.();
            setIsOpen(false);
            setUploads([]);
            queryClient.invalidateQueries({ queryKey: ['tariff-batches'] });
            queryClient.invalidateQueries({ queryKey: ['tariff-versions'] });

        } catch (err: any) {
            toast({
                variant: "destructive",
                title: "Error creating batch",
                description: err.message
            });
        }
    };

    const isUploading = createBatchMutation.isPending || uploads.some(u => u.status === 'uploading' || u.status === 'processing');

    // Escape key to close
    useEffect(() => {
        const handleEsc = (e: KeyboardEvent) => {
            if (e.key === 'Escape' && !isUploading) setIsOpen(false);
        };
        window.addEventListener('keydown', handleEsc);
        return () => window.removeEventListener('keydown', handleEsc);
    }, [isUploading]);

    return (
        <>
            <button
                onClick={() => setIsOpen(true)}
                style={{
                    display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                    borderRadius: '0.375rem', fontSize: '0.875rem', fontWeight: 500,
                    padding: '0.5rem 1rem', backgroundColor: '#111827', color: 'white',
                    border: 'none', cursor: 'pointer'
                }}
            >
                <Upload size={16} style={{ marginRight: '0.5rem' }} />
                Subir Tarifas
            </button>

            {isOpen && (
                <div style={{
                    position: 'fixed', inset: 0, zIndex: 50, backgroundColor: 'rgba(0, 0, 0, 0.5)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '1rem'
                }}>
                    <div style={{
                        backgroundColor: 'white', borderRadius: '0.5rem', width: '100%', maxWidth: '500px',
                        boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)',
