                        </div>

                        <div style={{ padding: '0 1.5rem 1.5rem 1.5rem' }}>
                            <div className="grid gap-4 py-4">
                                <div
                                    style={{
                                        border: '2px dashed #e5e7eb', borderRadius: '0.5rem', padding: '2rem',
                                        textAlign: 'center', transition: 'background-color 0.2s',
                                        cursor: isUploading ? 'not-allowed' : 'pointer',
                                        opacity: isUploading ? 0.5 : 1,
                                        backgroundColor: '#f9fafb'
                                    }}
                                    onMouseEnter={(e) => { if (!isUploading) e.currentTarget.style.backgroundColor = '#f3f4f6'; }}
                                    onMouseLeave={(e) => { if (!isUploading) e.currentTarget.style.backgroundColor = '#f9fafb'; }}
                                    onClick={() => fileInputRef.current?.click()}
                                >
                                    <input
                                        type="file"
                                        ref={fileInputRef}
                                        style={{ display: 'none' }}
                                        accept="application/pdf"
                                        multiple
                                        onChange={handleFileSelect}
                                    />
                                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '0.5rem', color: '#64748b' }}>
                                        <Upload size={32} />
                                        <p style={{ fontSize: '0.875rem', fontWeight: 500, margin: 0 }}>Haz clic para seleccionar PDFs</p>
                                        <p style={{ fontSize: '0.75rem', margin: 0 }}>M├íximo 10MB por archivo</p>
                                    </div>
                                </div>

                                {uploads.length > 0 && (
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem', maxHeight: '300px', overflowY: 'auto', paddingRight: '0.5rem' }}>
                                        {uploads.map((upload, index) => (
                                            <div key={index} style={{
                                                display: 'flex', alignItems: 'center', gap: '0.75rem',
                                                backgroundColor: '#f8fafc', padding: '0.75rem', borderRadius: '0.375rem',
                                                border: '1px solid #e2e8f0', fontSize: '0.875rem'
                                            }}>
                                                <FileText size={16} style={{ color: '#3b82f6', flexShrink: 0 }} />
                                                <div style={{ flex: 1, minWidth: 0 }}>
                                                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.25rem' }}>
                                                        <span style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', fontWeight: 500 }}>{upload.file.name}</span>
                                                        <span style={{ fontSize: '0.75rem', color: '#64748b', textTransform: 'capitalize' }}>{upload.status}</span>
                                                    </div>

                                                    {/* Custom Progress Bar */}
                                                    <div style={{ height: '0.375rem', width: '100%', backgroundColor: '#e2e8f0', borderRadius: '9999px', overflow: 'hidden' }}>
                                                        <div style={{
                                                            height: '100%', backgroundColor: '#111827', width: `${upload.progress}%`,
                                                            transition: 'width 0.3s ease'
                                                        }} />
                                                    </div>

                                                    {upload.error && (
                                                        <p style={{ fontSize: '0.75rem', color: '#ef4444', marginTop: '0.25rem' }}>{upload.error}</p>
                                                    )}
                                                </div>
                                                {!isUploading && (
                                                    <button onClick={() => removeFile(index)} style={{ color: '#94a3b8', background: 'none', border: 'none', cursor: 'pointer' }}>
                                                        <X size={16} />
                                                    </button>
                                                )}
                                                {upload.status === 'completed' && <CheckCircle2 size={16} style={{ color: '#22c55e' }} />}
                                                {upload.status === 'error' && <AlertCircle size={16} style={{ color: '#ef4444' }} />}
                                                {(upload.status === 'uploading' || upload.status === 'processing') && <Loader2 size={16} className="animate-spin" style={{ color: '#3b82f6' }} />}
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>

                            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '0.75rem' }}>
                                <button
                                    onClick={() => setIsOpen(false)}
                                    disabled={isUploading}
                                    style={{
                                        display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                                        borderRadius: '0.375rem', fontSize: '0.875rem', fontWeight: 500,
                                        padding: '0.5rem 1rem', backgroundColor: 'white', color: '#1f2937',
                                        border: '1px solid #e5e7eb', cursor: isUploading ? 'not-allowed' : 'pointer'
                                    }}
                                >
                                    Cancelar
                                </button>
                                <button
                                    onClick={startUpload}
                                    disabled={uploads.length === 0 || isUploading}
                                    style={{
                                        display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                                        borderRadius: '0.375rem', fontSize: '0.875rem', fontWeight: 500,
                                        padding: '0.5rem 1rem', backgroundColor: '#111827', color: 'white',
                                        border: 'none', cursor: (uploads.length === 0 || isUploading) ? 'not-allowed' : 'pointer',
                                        opacity: (uploads.length === 0 || isUploading) ? 0.7 : 1
                                    }}
                                >
                                    {isUploading ? (
                                        <>
                                            <Loader2 size={16} className="animate-spin" style={{ marginRight: '0.5rem' }} />
                                            Procesando...
                                        </>
                                    ) : (
                                        'Iniciar Subida'
                                    )}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
}

import { useState } from 'react';
import { useToast } from '@/hooks/use-toast';
import { supabase } from '@/shared/lib/supabase';
import { Loader2, Upload } from 'lucide-react';
import { cn } from '@/shared/lib/utils';
import { DetectedTariff } from '@/types/tariff';

interface Step1UploadProps {
    onTariffsDetected: (newCandidates: DetectedTariff[], file: File) => void;
    onManualEntry: () => void;
}

export function Step1Upload({ onTariffsDetected, onManualEntry }: Step1UploadProps) {
    const { toast } = useToast();
    const [processing, setProcessing] = useState(false);

    // PDF Viewer State (Local to upload step for previewing BEFORE parsing?)
    // Actually, user wants preview alongside parsing?
    // In the previous code, preview was always visible.
    // Let's keep it simple: Upload -> Process -> Result.

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (processing) return;
        if (e.target.files && e.target.files[0]) {
            const selectedFile = e.target.files[0];
            processFile(selectedFile);
        }
    };

    const processFile = async (f: File) => {
        setProcessing(true);
        try {
            if (!f.type.includes('pdf') && !f.type.includes('image')) {
                toast({ variant: 'destructive', title: 'Error', description: 'Por favor sube un PDF o una Imagen.' });
                setProcessing(false);
                return;
            }

            const { data: { session }, error: sessionError } = await supabase.auth.refreshSession();
            if (sessionError || !session) throw new Error("Sesi├│n expirada.");

            const formData = new FormData();
            formData.append('file', f);

            const { data: extracted, error } = await supabase.functions.invoke('parse-tariff-document', {
                body: formData
            });

            if (error) throw error;
            if (!extracted) throw new Error("No se recibieron datos de la IA");

            const newCandidates: DetectedTariff[] = [];
            const rawTariffs = extracted.tariffs && Array.isArray(extracted.tariffs) ? extracted.tariffs : [extracted];

            rawTariffs.forEach((t: any) => {
                // Normalize contract_duration to number (months)
                let duration: number | null = null;
                if (t.contract_duration != null) {
                    if (typeof t.contract_duration === 'number') {
                        duration = t.contract_duration;
                    } else {
                        // Legacy: parse "12 meses", "1 a├▒o", "24 meses", etc.
                        const str = String(t.contract_duration).toLowerCase().trim();
                        const monthsMatch = str.match(/(\d+)\s*mes/);
                        const yearsMatch = str.match(/(\d+)\s*a[├▒n]o/);
                        if (monthsMatch) duration = parseInt(monthsMatch[1]);
                        else if (yearsMatch) duration = parseInt(yearsMatch[1]) * 12;
                        else {
                            const num = parseInt(str);
                            if (!isNaN(num)) duration = num;
                        }
                    }
                }

                // Build price_sets: use new format or wrap legacy flat arrays
                let priceSets: DetectedTariff['price_sets'] = [];
                if (t.price_sets && Array.isArray(t.price_sets) && t.price_sets.length > 0) {
                    priceSets = t.price_sets.map((ps: any) => {
                        // Parse per-set contract_duration, falling back to the root tariff duration
                        let setDuration: number | null = null;
                        if (ps.contract_duration != null) {
                            setDuration = typeof ps.contract_duration === 'number'
                                ? ps.contract_duration
                                : parseInt(String(ps.contract_duration), 10) || null;
                        } else {
                            setDuration = duration; // Inherit from root tariff
                        }

                        return {
                            contract_duration: setDuration,
                            valid_from: ps.valid_from || undefined,
                            valid_to: ps.valid_to || undefined,
                            energy_prices: ps.energy_prices || [],
                            power_prices: ps.power_prices || [],
                            fixed_term_prices: ps.fixed_term_prices || [],
                        };
                    });
                } else {
                    // Legacy fallback: single price_set from flat arrays
                    priceSets = [{
                        contract_duration: duration,
                        valid_from: t.validity_date || undefined,
                        valid_to: undefined,
                        energy_prices: t.energy_prices || [],
                        power_prices: t.power_prices || [],
                        fixed_term_prices: t.fixed_term_prices || [],
                    }];
                }

                // Build legacy flat arrays from first price_set for UI display compat
                const firstSet = priceSets[0] || { energy_prices: [], power_prices: [], fixed_term_prices: [] };

                newCandidates.push({
                    id: crypto.randomUUID(),
                    fileName: f.name,
                    supplier_name: t.supplier_name,
                    tariff_name: t.tariff_name,
                    tariff_structure: t.tariff_structure,
                    supply_type: t.supply_type || undefined,
                    contract_duration: duration,
                    is_indexed: t.is_indexed,
                    price_sets: priceSets,
                    energy_prices: firstSet.energy_prices,
                    power_prices: firstSet.power_prices,
                    fixed_term_prices: firstSet.fixed_term_prices,
                });
            });

            onTariffsDetected(newCandidates, f);
            toast({ title: "An├ílisis Completado", description: `Se han detectado ${newCandidates.length} tarifa(s).` });

        } catch (err: any) {
            console.error('Error parsing document:', err);
            toast({ variant: 'destructive', title: 'Error', description: err.message || 'Error al analizar el documento.' });
        } finally {
            setProcessing(false);
        }
    };

    return (
        <div className="flex flex-col items-center justify-center min-h-[400px]">
            <div className="w-full max-w-md">
                <div className={cn(
                    "border-2 dashed rounded-lg p-10 text-center transition-colors cursor-pointer",
                    processing ? "border-blue-300 bg-blue-50" : "border-gray-300 hover:bg-gray-50"
                )}>
                    {processing ? (
                        <div className="flex flex-col items-center py-4">
                            <Loader2 size={48} className="animate-spin text-blue-500 mb-4" />
                            <span className="text-lg font-medium text-blue-700">Analizando documento...</span>
                        </div>
                    ) : (
                        <div className="flex flex-col items-center relative">
                            <Upload size={48} className="text-gray-400 mb-4" />
                            <h3 className="text-xl font-medium text-gray-900 mb-2">Subir factura o contrato</h3>
                            <p className="text-gray-500 mb-6">PDF, PNG o JPG hasta 10MB</p>

                            <div className="relative w-full">
                                <button className="btn btn-primary w-full pointer-events-none">
                                    Seleccionar Archivo
                                </button>
                                <input
                                    type="file"
                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                                    accept=".pdf,image/*"
                                    onChange={handleFileChange}
                                    value=""
                                />
                            </div>
                        </div>
                    )}
                </div>

                <div className="mt-6 text-center">
                    <span className="text-gray-400 text-sm">┬┐Prefieres introducir los datos a mano?</span>
                    <button onClick={onManualEntry} className="text-blue-600 font-medium text-sm ml-2 hover:underline">
                        Entrada Manual
                    </button>
                </div>
            </div>
        </div>
    );
}

import { useEffect, useState, useMemo } from 'react';
import { TariffRate, TariffStructure, TariffWizardState } from '@/types/tariff';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/shared/components/ui/tabs';
import { Plus, Trash2, Clock } from 'lucide-react';
import { ValidityPriceGroup } from './ValidityPriceGroup';

interface Step3AProps {
    data: TariffWizardState;
    structure: TariffStructure | undefined;
    onChange: (rates: TariffRate[]) => void;
    onAddDuration: (months: number) => string | undefined;
    onAddValidityPeriod: (durationKey: string, validFrom: string) => void;
    onDeleteDuration: (durationKey: string) => void;
    onDeleteValidityGroup: (durationKey: string, validFrom: string | null, validTo: string | null) => void;
    onUpdateValidity: (durationKey: string, oldFrom: string | null, oldTo: string | null, newFrom: string | null, newTo: string | null) => void;
}

export function Step3AEnergyPrices({ data, structure, onChange, onAddDuration, onAddValidityPeriod, onDeleteDuration, onDeleteValidityGroup, onUpdateValidity }: Step3AProps) {
    const [activeTab, setActiveTab] = useState<string>("default");
    const [newDuration, setNewDuration] = useState<string>("12");

    const energyRates = useMemo(() => {
        return data.rates.filter(r => r.item_type === 'energy');
    }, [data.rates]);

    // Group by Duration
    const ratesByDuration = useMemo(() => {
        const grouped = new Map<string, TariffRate[]>();
        energyRates.forEach(r => {
            const key = r.contract_duration ? r.contract_duration.toString() : "any";
            if (!grouped.has(key)) grouped.set(key, []);
            grouped.get(key)!.push(r);
        });
        return new Map([...grouped.entries()].sort((a, b) => {
            if (a[0] === 'any') return -1;
            if (b[0] === 'any') return 1;
            return parseInt(a[0]) - parseInt(b[0]);
        }));
    }, [energyRates]);

    useEffect(() => {
        const keys = Array.from(ratesByDuration.keys());
        if (keys.length > 0 && !ratesByDuration.has(activeTab) && activeTab !== 'default') {
            setActiveTab(keys[0]);
        } else if (keys.length > 0 && activeTab === 'default') {
            setActiveTab(keys[0]);
        }
    }, [ratesByDuration, activeTab]);

    const handleAddDuration = () => {
        const months = parseInt(newDuration);
        if (isNaN(months) || months <= 0) return;
        onAddDuration(months);
        setActiveTab(months.toString());
    };

    const handleAddValidityPeriod = (durationKey: string) => {
        const today = new Date().toISOString().split('T')[0];
        onAddValidityPeriod(durationKey, today);
    };

    const updateRate = (id: string, field: keyof TariffRate, value: any) => {
        const newRates = data.rates.map(r => r.id === id ? { ...r, [field]: value } : r);
        onChange(newRates);
    };

    const updateValidity = (ids: string[], validFrom: string | null, validTo: string | null) => {
        // Find the duration key and old validity from the first rate in the group
        const firstRate = data.rates.find(r => ids.includes(r.id));
        if (!firstRate) return;
        const durationKey = firstRate.contract_duration ? firstRate.contract_duration.toString() : 'any';
        const oldFrom = firstRate.valid_from || null;
        const oldTo = firstRate.valid_to || null;
        onUpdateValidity(durationKey, oldFrom, oldTo, validFrom, validTo);
    };

    // Group by validity within a duration
    const getRatesByValidity = (rates: TariffRate[]) => {
        const grouped = new Map<string, TariffRate[]>();
        rates.forEach(r => {
            const key = JSON.stringify({ from: r.valid_from || null, to: r.valid_to || null });
            if (!grouped.has(key)) grouped.set(key, []);
            grouped.get(key)!.push(r);
        });
        return Array.from(grouped.entries()).sort((a, b) => {
            const dateA = JSON.parse(a[0]).from || '1900-01-01';
            const dateB = JSON.parse(b[0]).from || '1900-01-01';
            return dateA.localeCompare(dateB);
        });
    };

    if (!structure) return <div>Selecciona una estructura en el paso 1.</div>;

    const durationKeys = Array.from(ratesByDuration.keys());

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            <div>
                <h2 style={{ fontSize: '1.25rem', fontWeight: 600, color: '#111827', margin: 0 }}>Precios de Energ├¡a</h2>
                <p style={{ fontSize: '0.875rem', color: '#6b7280', margin: '0.25rem 0 0 0' }}>
                    Las duraciones y periodos de vigencia se sincronizan con Precios de Potencia.
                </p>
            </div>

            <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
                <div className="flex items-center gap-2 mb-4 overflow-x-auto pb-2">
                    <TabsList className="bg-slate-100 p-1 rounded-lg">
                        {durationKeys.map(key => (
                            <TabsTrigger key={key} value={key}
                                className="px-4 py-2 rounded-md data-[state=active]:bg-white data-[state=active]:shadow-sm transition-all text-sm font-medium">
                                {key === 'any' ? 'Est├índar (Base)' : `${key} Meses`}
                            </TabsTrigger>
                        ))}
                    </TabsList>

                    <div className="flex items-center gap-2 ml-2">
                        <select
                            className="w-32 px-2 py-1 text-sm border rounded-md"
                            value={newDuration}
                            onChange={(e) => setNewDuration(e.target.value)}
                        >
                            <option value="12">12 Meses</option>
                            <option value="24">24 Meses</option>
                            <option value="36">36 Meses</option>
                        </select>
                        <button type="button" onClick={handleAddDuration}
                            className="p-2 text-primary hover:bg-slate-100 rounded-full transition-colors"
                            title="A├▒adir duraci├│n">
                            <Plus size={18} />
                        </button>
                    </div>
                </div>

                {durationKeys.length === 0 && (
                    <div style={{ padding: '2rem', textAlign: 'center', color: '#6b7280', background: '#f9fafb', borderRadius: '0.5rem' }}>
                        No hay precios configurados. A├▒ade una duraci├│n.
                    </div>
                )}

                {durationKeys.map(key => {
                    const currentDurationRates = ratesByDuration.get(key) || [];
                    const validityGroups = getRatesByValidity(currentDurationRates);

                    return (
                        <TabsContent key={key} value={key} className="space-y-6 animate-in fade-in-50 duration-300">
                            <div className="flex justify-between items-center bg-slate-50 p-3 rounded-lg border border-slate-100 mb-4">
                                <div className="flex items-center gap-2 text-sm text-slate-600">
                                    <Clock size={16} />
                                    <span>Configurando: <strong>{key === 'any' ? 'Cualquier duraci├│n' : `${key} meses`}</strong></span>
                                </div>
                                <button type="button"
                                    onClick={() => { if (confirm('┬┐Eliminar esta duraci├│n de energ├¡a Y potencia?')) onDeleteDuration(key); }}
                                    className="text-red-500 hover:text-red-700 text-xs flex items-center gap-1 px-2 py-1 bg-white border border-red-100 rounded hover:bg-red-50">
                                    <Trash2 size={12} /> Eliminar duraci├│n
                                </button>
                            </div>

                            {validityGroups.map(([validityKey, groupRates]) => (
                                <ValidityPriceGroup
                                    key={validityKey}
                                    rates={groupRates}
                                    onUpdateRate={(id, field, val) => updateRate(id, field, val)}
                                    onUpdateValidity={(f, t) => updateValidity(groupRates.map(r => r.id), f, t)}
                                    onDelete={() => {
                                        const parsed = JSON.parse(validityKey);
                                        onDeleteValidityGroup(key, parsed.from, parsed.to);
                                    }}
                                />
                            ))}

                            <button type="button" onClick={() => handleAddValidityPeriod(key)}
                                style={{
                                    width: '100%', padding: '1rem', border: '2px dashed #e2e8f0',
                                    borderRadius: '0.75rem', color: '#64748b', fontWeight: 500,
                                    cursor: 'pointer', display: 'flex', alignItems: 'center',
                                    justifyContent: 'center', gap: '0.5rem', marginTop: '1rem', background: 'none'
                                }}>
                                <Plus size={20} /> A├▒adir periodo de vigencia (crea energ├¡a + potencia)
                            </button>
                        </TabsContent>
                    );
                })}
            </Tabs>
        </div>
    );
}

import { useEffect, useState, useMemo } from 'react';
import { TariffRate, TariffStructure, TariffWizardState } from '@/types/tariff';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/shared/components/ui/tabs';
import { Plus, Trash2, Clock } from 'lucide-react';
import { ValidityPriceGroup } from './ValidityPriceGroup';

interface Step3BProps {
    data: TariffWizardState;
    structure: TariffStructure | undefined;
    onChange: (rates: TariffRate[]) => void;
    onAddDuration: (months: number) => string | undefined;
    onAddValidityPeriod: (durationKey: string, validFrom: string) => void;
    onDeleteDuration: (durationKey: string) => void;
    onDeleteValidityGroup: (durationKey: string, validFrom: string | null, validTo: string | null) => void;
    onUpdateValidity: (durationKey: string, oldFrom: string | null, oldTo: string | null, newFrom: string | null, newTo: string | null) => void;
}

export function Step3BPowerPrices({ data, structure, onChange, onAddDuration, onAddValidityPeriod, onDeleteDuration, onDeleteValidityGroup, onUpdateValidity }: Step3BProps) {
    const [activeTab, setActiveTab] = useState<string>("default");
    const [newDuration, setNewDuration] = useState<string>("12");

    const powerRates = useMemo(() => {
        return data.rates.filter(r => r.item_type === 'power');
    }, [data.rates]);

    // Group by Duration
    const ratesByDuration = useMemo(() => {
        const grouped = new Map<string, TariffRate[]>();
        powerRates.forEach(r => {
            const key = r.contract_duration ? r.contract_duration.toString() : "any";
            if (!grouped.has(key)) grouped.set(key, []);
            grouped.get(key)!.push(r);
        });
        return new Map([...grouped.entries()].sort((a, b) => {
            if (a[0] === 'any') return -1;
            if (b[0] === 'any') return 1;
            return parseInt(a[0]) - parseInt(b[0]);
        }));
    }, [powerRates]);

    useEffect(() => {
        const keys = Array.from(ratesByDuration.keys());
        if (keys.length > 0 && !ratesByDuration.has(activeTab) && activeTab !== 'default') {
            setActiveTab(keys[0]);
        } else if (keys.length > 0 && activeTab === 'default') {
            setActiveTab(keys[0]);
        }
    }, [ratesByDuration, activeTab]);

    const handleAddDuration = () => {
        const months = parseInt(newDuration);
        if (isNaN(months) || months <= 0) return;
        onAddDuration(months);
        setActiveTab(months.toString());
    };

    const handleAddValidityPeriod = (durationKey: string) => {
        const today = new Date().toISOString().split('T')[0];
        onAddValidityPeriod(durationKey, today);
    };

    const updateRate = (id: string, field: keyof TariffRate, value: any) => {
        const newRates = data.rates.map(r => {
            if (r.id === id) {
                if (field === 'price' && typeof value === 'number') return { ...r, price: value };
                if (field === 'unit' && typeof value === 'string') return { ...r, unit: value };
                return { ...r, [field]: value };
            }
            return r;
        });
        onChange(newRates);
    };

    const updateValidity = (ids: string[], validFrom: string | null, validTo: string | null) => {
        const firstRate = data.rates.find(r => ids.includes(r.id));
        if (!firstRate) return;
        const durationKey = firstRate.contract_duration ? firstRate.contract_duration.toString() : 'any';
        const oldFrom = firstRate.valid_from || null;
        const oldTo = firstRate.valid_to || null;
        onUpdateValidity(durationKey, oldFrom, oldTo, validFrom, validTo);
    };

    const getRatesByValidity = (rates: TariffRate[]) => {
        const grouped = new Map<string, TariffRate[]>();
        rates.forEach(r => {
            const key = JSON.stringify({ from: r.valid_from || null, to: r.valid_to || null });
            if (!grouped.has(key)) grouped.set(key, []);
            grouped.get(key)!.push(r);
        });
        return Array.from(grouped.entries()).sort((a, b) => {
            const dateA = JSON.parse(a[0]).from || '1900-01-01';
            const dateB = JSON.parse(b[0]).from || '1900-01-01';
            return dateA.localeCompare(dateB);
        });
    };

    if (!structure) return <div>Selecciona una estructura en el paso 1.</div>;

    const labelStyle = { display: 'block', fontSize: '0.75rem', fontWeight: 500, color: '#374151', marginBottom: '0.25rem' };
    const inputStyle = {
        width: '100%', padding: '0.5rem', borderRadius: '0.375rem',
        border: '1px solid #d1d5db', fontSize: '0.875rem', outline: 'none',
        transition: 'border-color 0.15s ease-in-out'
    };

    const durationKeys = Array.from(ratesByDuration.keys());

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            <div>
                <h2 style={{ fontSize: '1.25rem', fontWeight: 600, color: '#111827', margin: 0 }}>Precios de Potencia (T├®rmino Fijo)</h2>
                <p style={{ fontSize: '0.875rem', color: '#6b7280', margin: '0.25rem 0 0 0' }}>
                    Las duraciones y periodos de vigencia se sincronizan con Precios de Energ├¡a.
                </p>
            </div>

            <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
                <div className="flex items-center gap-2 mb-4 overflow-x-auto pb-2">
                    <TabsList className="bg-slate-100 p-1 rounded-lg">
                        {durationKeys.map(key => (
                            <TabsTrigger key={key} value={key}
                                className="px-4 py-2 rounded-md data-[state=active]:bg-white data-[state=active]:shadow-sm transition-all text-sm font-medium">
                                {key === 'any' ? 'Est├índar (Base)' : `${key} Meses`}
                            </TabsTrigger>
                        ))}
                    </TabsList>

                    <div className="flex items-center gap-2 ml-2">
                        <select
                            className="w-32 px-2 py-1 text-sm border rounded-md"
                            value={newDuration}
                            onChange={(e) => setNewDuration(e.target.value)}
                        >
                            <option value="12">12 Meses</option>
                            <option value="24">24 Meses</option>
                            <option value="36">36 Meses</option>
                        </select>
                        <button type="button" onClick={handleAddDuration}
                            className="p-2 text-primary hover:bg-slate-100 rounded-full transition-colors"
                            title="A├▒adir duraci├│n">
                            <Plus size={18} />
                        </button>
                    </div>
                </div>

                {durationKeys.length === 0 && (
                    <div style={{ padding: '2rem', textAlign: 'center', color: '#6b7280', background: '#f9fafb', borderRadius: '0.5rem' }}>
                        No hay precios configurados. A├▒ade una duraci├│n.
                    </div>
                )}

                {durationKeys.map(key => {
                    const currentRates = ratesByDuration.get(key) || [];
                    const validityGroups = getRatesByValidity(currentRates);

                    return (
                        <TabsContent key={key} value={key} className="space-y-6 animate-in fade-in-50 duration-300">
                            <div className="flex justify-between items-center bg-slate-50 p-3 rounded-lg border border-slate-100 mb-4">
                                <div className="flex items-center gap-2 text-sm text-slate-600">
                                    <Clock size={16} />
                                    <span>Configurando: <strong>{key === 'any' ? 'Cualquier duraci├│n' : `${key} meses`}</strong></span>
                                </div>
                                <button type="button"
                                    onClick={() => { if (confirm('┬┐Eliminar esta duraci├│n de energ├¡a Y potencia?')) onDeleteDuration(key); }}
                                    className="text-red-500 hover:text-red-700 text-xs flex items-center gap-1 px-2 py-1 bg-white border border-red-100 rounded hover:bg-red-50">
                                    <Trash2 size={12} /> Eliminar
                                </button>
                            </div>

                            {validityGroups.map(([validityKey, groupRates]) => (
                                <ValidityPriceGroup
                                    key={validityKey}
                                    rates={groupRates}
                                    onUpdateRate={(id, field, val) => updateRate(id, field, val)}
                                    onUpdateValidity={(f, t) => updateValidity(groupRates.map(r => r.id), f, t)}
                                    onDelete={() => {
                                        const parsed = JSON.parse(validityKey);
                                        onDeleteValidityGroup(key, parsed.from, parsed.to);
                                    }}
                                    showUnitSelector={true}
                                    unitOptions={[
                                        { value: 'EUR/kW/year', label: 'Ôé¼/kW/a├▒o' },
                                        { value: 'EUR/kW/day', label: 'Ôé¼/kW/d├¡a' },
                                        { value: 'EUR/kW/month', label: 'Ôé¼/kW/mes' }
                                    ]}
                                />
                            ))}

                            <button type="button" onClick={() => handleAddValidityPeriod(key)}
                                style={{
                                    width: '100%', padding: '1rem', border: '2px dashed #e2e8f0',
                                    borderRadius: '0.75rem', color: '#64748b', fontWeight: 500,
                                    cursor: 'pointer', display: 'flex', alignItems: 'center',
                                    justifyContent: 'center', gap: '0.5rem', marginTop: '1rem', background: 'none'
                                }}>
                                <Plus size={20} /> A├▒adir periodo de vigencia (crea energ├¡a + potencia)
                            </button>
                        </TabsContent>
                    );
                })}
            </Tabs>

            {/* Excess Power ÔÇö always separate, not duration/validity dependent */}
            <div style={{ padding: '1.5rem', background: '#f0fdf4', borderRadius: '0.5rem', border: '1px solid #dcfce7', marginTop: '1rem' }}>
                <h3 style={{ fontSize: '1rem', fontWeight: 600, color: '#166534', marginBottom: '0.5rem' }}>Excesos de Potencia / M├íximo Demandado</h3>
                <div style={{ display: 'grid', gridTemplateColumns: 'minmax(200px, 300px)', gap: '1rem' }}>
                    <div>
                        <label style={labelStyle}>Precio Exceso (Ôé¼/kW/d├¡a)</label>
                        <input
                            type="number" step="0.000001" style={inputStyle}
                            placeholder="Ej: 0.054321"
                            value={data.rates.find(r => r.item_type === 'excess_power')?.price || ''}
                            onChange={(e) => {
                                const val = parseFloat(e.target.value);
                                const otherRates = data.rates.filter(r => r.item_type !== 'excess_power');
                                const excessRate: TariffRate = {
                                    id: data.rates.find(r => r.item_type === 'excess_power')?.id || crypto.randomUUID(),
                                    tariff_version_id: '', item_type: 'excess_power',
                                    price: isNaN(val) ? null : val,
                                    unit: 'EUR/kW/day', confidence_score: 1.0, contract_duration: null
                                };
                                onChange([...otherRates, excessRate]);
                            }}
                        />
                    </div>
                </div>
                <p style={{ fontSize: '0.75rem', color: '#166534', marginTop: '0.5rem', opacity: 0.8 }}>
                    Este precio se aplica a los excesos registrados por el max├¡metro o telemedida.
                </p>
            </div>
        </div>
    );
}

import { TariffRate, TariffWizardState } from '@/types/tariff';
import { Plus, Trash2 } from 'lucide-react';

interface Step5Props {
    data: TariffWizardState;
    onChange: (rates: TariffRate[]) => void;
}

export function Step5FeesAndTaxes({ data, onChange }: Step5Props) {
    const feesAndTaxes = data.rates.filter(r => ['fixed_fee', 'tax', 'discount'].includes(r.item_type));

    const addRate = (type: 'fixed_fee' | 'tax' | 'discount') => {
        const newRate: TariffRate = {
            id: crypto.randomUUID(),
            tariff_version_id: '',
            item_type: type,
            price: 0,
            unit: type === 'fixed_fee' ? 'EUR/month' : '%',
        };
        onChange([...data.rates, newRate]);
    };

    const removeRate = (id: string) => {
        onChange(data.rates.filter(r => r.id !== id));
    };

    const updateRate = <K extends keyof TariffRate>(id: string, field: K, value: TariffRate[K]) => {
        const updatedRates = data.rates.map(r => r.id === id ? { ...r, [field]: value } : r);
        onChange(updatedRates);
    };

    const labelStyle = { display: 'block', fontSize: '0.75rem', fontWeight: 500, color: '#374151', marginBottom: '0.25rem' };
    const inputStyle = {
        width: '100%',
        padding: '0.375rem 0.5rem',
        borderRadius: '0.375rem',
        border: '1px solid #d1d5db',
        fontSize: '0.875rem',
        outline: 'none'
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            <h2 style={{ fontSize: '1.25rem', fontWeight: 600, color: '#111827', margin: 0 }}>Cargos Extra e Impuestos</h2>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                {feesAndTaxes.map((rate) => (
                    <div key={rate.id} className="card" style={{ padding: '1rem', display: 'flex', gap: '1rem', alignItems: 'flex-end', background: 'white', border: '1px solid #e5e7eb', borderRadius: '0.5rem' }}>
                        <div style={{ flex: 1 }}>
                            <label style={labelStyle}>Tipo</label>
                            <select
                                style={inputStyle}
                                value={rate.item_type}
                                onChange={(e) => updateRate(rate.id, 'item_type', e.target.value as any)}
                            >
                                <option value="fixed_fee">Cuota Fija</option>
                                <option value="tax">Impuesto</option>
                                <option value="discount">Descuento</option>
                            </select>
                        </div>
                        <div style={{ flex: 1 }}>
                            <label style={labelStyle}>Valor</label>
                            <input
                                type="number"
                                style={inputStyle}
                                value={rate.price || ''}
                                onChange={(e) => updateRate(rate.id, 'price', parseFloat(e.target.value))}
                            />
                        </div>
                        <div style={{ width: '6rem' }}>
                            <label style={labelStyle}>Unidad</label>
                            <select
                                style={inputStyle}
                                value={rate.unit}
                                onChange={(e) => updateRate(rate.id, 'unit', e.target.value)}
                            >
                                <option value="EUR/month">Ôé¼/mes</option>
                                <option value="EUR/day">Ôé¼/d├¡a</option>
                                <option value="%">%</option>
                            </select>
                        </div>
                        <button
                            onClick={() => removeRate(rate.id)}
                            style={{
                                border: 'none',
                                background: 'transparent',
                                color: '#ef4444',
                                cursor: 'pointer',
                                padding: '0.5rem',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center'
                            }}
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                ))}

                {feesAndTaxes.length === 0 && (
                    <p style={{ color: '#6b7280', fontSize: '0.875rem', fontStyle: 'italic', margin: 0 }}>No hay cargos extra configurados.</p>
                )}
            </div>

            <div style={{ display: 'flex', gap: '0.5rem' }}>
                <button onClick={() => addRate('fixed_fee')} className="btn btn-secondary" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <Plus size={16} /> A├▒adir Cuota
                </button>
                <button onClick={() => addRate('tax')} className="btn btn-secondary" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <Plus size={16} /> A├▒adir Impuesto
                </button>
            </div>
        </div>
    );
}

import { TariffWizardState } from '@/types/tariff';
import { CheckCircle2, AlertTriangle, Loader2 } from 'lucide-react';
import { supabase } from '@/shared/lib/supabase';
import { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useToast } from '@/hooks/use-toast';
import { ConfirmDialog } from '@/shared/components/ConfirmDialog';

interface Step6Props {
    data: TariffWizardState;
    mode?: 'create' | 'edit';
    onSave: () => void;
}

export function Step6Summary({ data, mode = 'create' }: Step6Props) {
    const navigate = useNavigate();
    const [saving, setSaving] = useState(false);
    const { toast } = useToast();
    const { id } = useParams();
    const [showDeleteDialog, setShowDeleteDialog] = useState(false);

    // Validation status
    const hasRates = data.rates && data.rates.length > 0;
    const isComplete = data.metadata.supplier_id && data.metadata.name && data.metadata.tariff_structure_id && hasRates;

    const handleDelete = async () => {
        if (!id) return;

        setSaving(true);
        try {
            const { error } = await supabase.from('tariff_versions').delete().eq('id', id);
            if (error) throw error;
            toast({ title: 'Tarifa eliminada', description: 'La tarifa ha sido eliminada correctamente.' });
            navigate('/admin/tariffs');
        } catch (error: any) {
            console.error(error);
            toast({ variant: 'destructive', title: 'Error', description: 'No se pudo eliminar la tarifa.' });
        } finally {
            setSaving(false);
            setShowDeleteDialog(false);
        }
    };

    const handleSave = async (activate: boolean) => {
        setSaving(true);
        try {
            // 1. Prepare Payload
            const { data: user } = await supabase.auth.getUser();
            const { data: company } = await supabase.from('users').select('company_id').eq('id', user.user!.id).single();

            const { data: selectedStructure } = await supabase
                .from('tariff_structures')
                .select('code')
                .eq('id', data.metadata.tariff_structure_id)
                .single();

            const payload = {
                company_id: company?.company_id,
                supplier_id: data.metadata.supplier_id,
                tariff_structure_id: data.metadata.tariff_structure_id,
                tariff_name: data.metadata.name,
                tariff_code: data.metadata.code,
                tariff_type: selectedStructure?.code || '2.0TD',
                is_indexed: data.metadata.is_indexed,
                valid_from: data.metadata.valid_from,
                is_active: activate,
                completion_status: isComplete ? 'complete' : 'draft'
            };

            let versionId = id;

            if (mode === 'create' || id) {
                // Use upsert to handle retries and updates uniformly
                const { data: version, error: vError } = await supabase
                    .from('tariff_versions')
                    .upsert(payload, {
                        onConflict: 'company_id, supplier_id, tariff_name, valid_from'
                    })
                    .select()
                    .single();

                if (vError) throw vError;
                versionId = version.id;
            }

            if (!versionId) throw new Error("No version ID");

            // 2. Handle Rates 
            // Always delete existing rates for this version before inserting new ones to ensure clean state
            await supabase.from('tariff_rates').delete().eq('tariff_version_id', versionId);

            const ratesPayload = data.rates.map(r => ({
                id: crypto.randomUUID(), // Always new IDs for rates
                tariff_version_id: versionId,
                item_type: r.item_type,
                period: r.period,
                price: r.price,
                price_formula: r.price_formula,
                unit: r.unit,
                confidence_score: r.confidence_score,
                contract_duration: r.contract_duration ?? null,
                valid_from: r.valid_from ?? data.metadata.valid_from ?? null,
                valid_to: r.valid_to ?? null
            }));

            if (ratesPayload.length > 0) {
                const { error: rError } = await supabase
                    .from('tariff_rates')
                    .insert(ratesPayload);
                if (rError) throw rError;
            }

            // 3. Insert Schedules
            // Always delete existing schedules for this version before inserting new ones
            await supabase.from('tariff_schedules').delete().eq('tariff_version_id', versionId);

            const schedulesPayload = data.schedules.map(s => ({
                id: crypto.randomUUID(), // Always new IDs for schedules
                tariff_version_id: versionId,
                month_mask: s.month_mask,
                day_type_mask: s.day_type_mask,
                start_hour: s.start_hour.includes(':') && s.start_hour.split(':').length === 2 ? `${s.start_hour}:00` : s.start_hour,
                end_hour: s.end_hour.includes(':') && s.end_hour.split(':').length === 2 ? `${s.end_hour}:59` : s.end_hour,
                period: s.period,
                context_calendar: s.context_calendar
            }));

            if (schedulesPayload.length > 0) {
                const { error: sError } = await supabase
                    .from('tariff_schedules')
                    .insert(schedulesPayload);
                if (sError) throw sError;
            }

            toast({
                title: mode === 'create' ? "Tarifa Creada" : "Tarifa Actualizada",
                description: `La tarifa ${data.metadata.name} ha sido guardada correctamente.`,
            });

            navigate('/admin/tariffs');

        } catch (err: any) {
            console.error(err);
            toast({
                variant: 'destructive',
                title: "Error al guardar",
                description: err.message,
            });
        } finally {
            setSaving(false);
        }
    };

    if (!data) return null;

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            <h2 style={{ fontSize: '1.25rem', fontWeight: 600, color: '#111827', margin: 0 }}>Resumen y Confirmaci├│n</h2>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '1.5rem' }}>
                <div className="card" style={{ padding: '1.5rem' }}>
                    <h3 style={{ fontWeight: 500, marginBottom: '1rem', color: '#111827', margin: '0 0 1rem 0' }}>Datos Generales</h3>
                    <dl style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', fontSize: '0.875rem', margin: 0 }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                            <dt style={{ color: '#6b7280' }}>Nombre:</dt>
                            <dd style={{ fontWeight: 500 }}>{data.metadata.name}</dd>
                        </div>
                        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                            <dt style={{ color: '#6b7280' }}>Modalidad:</dt>
                            <dd style={{ fontWeight: 500 }}>{data.metadata.is_indexed ? 'Indexado' : 'Fijo'}</dd>
                        </div>
                        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                            <dt style={{ color: '#6b7280' }}>Vigencia:</dt>
                            <dd style={{ fontWeight: 500 }}>{data.metadata.valid_from}</dd>
                        </div>
                    </dl>
                </div>

                <div className="card" style={{ padding: '1.5rem' }}>
                    <h3 style={{ fontWeight: 500, marginBottom: '1rem', color: '#111827', margin: '0 0 1rem 0' }}>Estado de Validaci├│n</h3>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.5rem' }}>
                        {isComplete ? (
                            <CheckCircle2 size={20} style={{ color: '#22c55e' }} />
                        ) : (
                            <AlertTriangle size={20} style={{ color: '#eab308' }} />
                        )}
                        <span style={{ fontWeight: 500 }}>
                            {isComplete ? 'Completa' : 'Faltan datos obligatorios (Metadata o Precios)'}
                        </span>
                    </div>
                    <p style={{ fontSize: '0.75rem', color: '#6b7280', margin: 0 }}>
                        {isComplete
                            ? "La tarifa est├í lista para ser activada y utilizada en recomendaciones."
                            : "Puedes guardar como borrador y terminar de editar m├ís tarde."}
                    </p>
                </div>
            </div>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingTop: '1.5rem', borderTop: '1px solid #e5e7eb' }}>
                {mode === 'edit' && (
                    <button
                        onClick={() => setShowDeleteDialog(true)}
                        disabled={saving}
                        className="btn btn-secondary"
                        style={{ color: '#ef4444', borderColor: '#fca5a5', background: '#fef2f2' }}
                    >
                        {saving ? <Loader2 size={16} className="animate-spin" /> : 'Eliminar Tarifa'}
                    </button>
                )}

                <div style={{ display: 'flex', gap: '0.75rem', marginLeft: 'auto' }}>
                    <button
                        className="btn btn-secondary"
                        onClick={() => handleSave(false)}
                        disabled={saving}
                    >
                        {saving ? <Loader2 size={16} className="animate-spin" /> : 'Guardar Borrador'}
                    </button>
                    <button
                        className="btn btn-primary"
                        onClick={() => handleSave(true)}
                        disabled={saving || !isComplete}
                    >
                        {saving ? <Loader2 size={16} className="animate-spin" /> : mode === 'edit' ? 'Actualizar Tarifa' : 'Publicar y Activar'}
                    </button>
                </div>
            </div>

            <ConfirmDialog
                isOpen={showDeleteDialog}
                title="Eliminar tarifa"
                message="┬┐Est├ís seguro de que quieres eliminar esta tarifa? Esta acci├│n no se puede deshacer."
                confirmLabel="Eliminar"
                variant="danger"
                onConfirm={handleDelete}
                onCancel={() => setShowDeleteDialog(false)}
            />
        </div>
    );
}

import { useParams, useNavigate } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/shared/lib/supabase';
import { Loader2, ArrowLeft, FileText, CheckCircle, AlertCircle, Clock } from 'lucide-react';


interface TariffFile {
    id: string;
    filename: string;
    status: string; // 'pending' | 'processing' | 'completed' | 'failed'
    file_size_bytes: number;
    created_at: string;
}

interface TariffBatch {
    id: string;
    status: string;
    file_count: number;
    created_at: string;
    files: TariffFile[];
}

export default function BatchDetailsPage() {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();

    const { data: batch, isLoading, error } = useQuery({
        queryKey: ['tariff-batch', id],
        queryFn: async () => {
            if (!id) throw new Error('No batch ID');

            // Fetch batch details
            const { data: batchData, error: batchError } = await supabase
                .from('tariff_batches')
                .select('*')
                .eq('id', id)
                .single();

            if (batchError) throw batchError;

            // Fetch files in batch
            const { data: filesData, error: filesError } = await supabase
                .from('tariff_files')
                .select('*')
                .eq('batch_id', id);

            if (filesError) throw filesError;

            return {
                ...batchData,
                files: filesData || []
            } as TariffBatch;
        },
        enabled: !!id,
        refetchInterval: (query) => {
            const data = query.state.data;
            // Poll if status is processing or uploaded
            if (data?.status === 'processing' || data?.status === 'uploaded') {
                return 2000;
            }
            return false;
        }
    });

    if (isLoading) {
        return (
            <div className="flex justify-center items-center h-96">
                <Loader2 size={32} className="animate-spin" style={{ color: '#3b82f6' }} />
            </div>
        );
    }

    if (error || !batch) {
        return (
            <div className="container mx-auto py-8 text-center text-red-500">
                <div style={{ fontSize: '1.25rem', fontWeight: 700, marginBottom: '0.5rem' }}>Error cargando el lote</div>
                <p style={{ marginBottom: '1rem' }}>{(error as any)?.message || 'Lote no encontrado'}</p>
                <button
                    onClick={() => navigate('/admin/tariffs')}
                    style={{
                        background: 'transparent', border: 'none', cursor: 'pointer',
                        color: '#4b5563', fontSize: '0.875rem', textDecoration: 'underline'
                    }}
                >
                    Volver
                </button>
            </div>
        );
    }



    const getStatusIcon = (status: string) => {
        switch (status) {
