    id: string;
    company_id: string;
    user_id?: string;
    full_name: string;
    email?: string;
    phone?: string;
    nif?: string;
    address?: string;
    commission_default_pct?: number;
    is_active: boolean;
    created_at: string;
    updated_at: string;
}

export interface Contract {
    id: string;
    company_id: string;
    customer_id: string;
    supply_point_id?: string;
